11	use work.psi_common_array_pkg.all;
12	use work.psi_common_math_pkg.all;
13	use work.psi_fix_pkg.all;
14	-- @formatter:off
15	entity psi_fix_cic_dec_fix_1ch is
16	  generic(
17	    order_g          : integer              := 4;                       -- CIC filter order
18	    ratio_g          : integer              := 10;                      -- CIC decimation ratio
19	    diff_delay_g     : natural range 1 to 2 := 1;                       -- differential delay
20	    in_fmt_g         : psi_fix_fmt_t        := (1, 0, 15);              -- input format FP
21	    out_fmt_g        : psi_fix_fmt_t        := (1, 0, 15);              -- output format FP
22	    rst_pol_g        : std_logic            := '1';                     -- reset polarity active high = '1'
23	    auto_gain_corr_g : boolean              := True                     -- Uses up to 25 bits of the datapath and 17 bit correction parameter
24	  );
25	  port(
26	    clk_i  : in  std_logic;                                              -- clk system
27	    rst_i  : in  std_logic;                                              -- rst system
28	    dat_i  : in  std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);  -- data input
29	    vld_i  : in  std_logic;                                              -- valid input Sampling frequency
30	    dat_o  : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0); -- data output
31	    vld_o  : out std_logic;                                              -- vaid output new Sampling frequency Fs/Ratio
32	    busy_o : out std_logic                                               -- active high - calc ongoing
33	  );
34	end entity;
35	-- @formatter:on
36	architecture rtl of psi_fix_cic_dec_fix_1ch is
37	  -- Constants
38	  constant CicGain_c    : real                                                     := (real(ratio_g) * real(diff_delay_g))**real(order_g);
39	  constant CicAddBits_c : integer                                                  := log2ceil(CicGain_c - 0.1); -- WORKAROUND: Vivado does real calculations imprecisely. With the -0.1, wrong results are avoided.
40	  constant Shift_c      : integer                                                  := CicAddBits_c;
41	  constant AccuFmt_c    : psi_fix_fmt_t                                            := (in_fmt_g.S, in_fmt_g.I + CicAddBits_c, in_fmt_g.F);
42	  constant DiffFmt_c    : psi_fix_fmt_t                                            := (out_fmt_g.S, in_fmt_g.I, out_fmt_g.F + order_g + 1);
43	  constant GcInFmt_c    : psi_fix_fmt_t                                            := (1, out_fmt_g.I, work.psi_common_math_pkg.min(24 - out_fmt_g.I, DiffFmt_c.F));
44	  constant GcCoefFmt_c  : psi_fix_fmt_t                                            := (0, 1, 16);
45	  constant GcMultFmt_c  : psi_fix_fmt_t                                            := (1, GcInFmt_c.I + GcCoefFmt_c.I, GcInFmt_c.F + GcCoefFmt_c.F);
46	  constant Gc_c         : std_logic_vector(psi_fix_size(GcCoefFmt_c) - 1 downto 0) := psi_fix_from_real(2.0**real(CicAddBits_c) / real(CicGain_c), GcCoefFmt_c);
47	
48	  -- Types
49	  type Accus_t is array (natural range <>) of std_logic_vector(psi_fix_size(AccuFmt_c) - 1 downto 0);
50	  type Diff_t is array (natural range <>) of std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
51	
52	  -- Two Process Method
53	  type two_process_r is record
54	    -- Accu Section
55	    Input_0     : std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);
56	    VldAccu     : std_logic_vector(0 to order_g);
57	    Accu        : Accus_t(1 to order_g);
58	    Rcnt        : integer range 0 to ratio_g - 1;
59	    -- Diff Section
60	    DiffIn_0    : std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
61	    VldDiff     : std_logic_vector(0 to order_g);
62	    DiffVal     : Diff_t(1 to order_g);
63	    DiffLast    : Diff_t(1 to order_g);
64	    DiffLast2   : Diff_t(1 to order_g);
65	    -- GC Stages
66	    GcVld       : std_logic_vector(0 to 2);
67	    GcIn_0      : std_logic_vector(psi_fix_size(GcInFmt_c) - 1 downto 0);
68	    GcMult_1    : std_logic_vector(psi_fix_size(GcMultFmt_c) - 1 downto 0);
69	    GcOut_2     : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
70	    -- Output
71	    Outp        : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
72	    OutVld      : std_logic;
73	    -- Status
74	    CalcOngoing : std_logic;
75	  end record;
76	  signal r, r_next : two_process_r;
77	
78	begin
79	  --------------------------------------------------------------------------
80	  -- Combinatorial Process
81	  --------------------------------------------------------------------------
82	  p_comb : process(r, dat_i, vld_i)
83	    variable v         : two_process_r;
84	    variable DiffDel_v : std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
85	  begin
86	    -- hold variables stable
87	    v         := r;
88	    DiffDel_v := (others => '0');
89	
90	    -- *** Pipe Handling ***
91	    v.VldAccu(v.VldAccu'low + 1 to v.VldAccu'high) := r.VldAccu(r.VldAccu'low to r.VldAccu'high - 1);
92	    v.VldDiff(v.VldDiff'low + 1 to v.VldDiff'high) := r.VldDiff(r.VldDiff'low to r.VldDiff'high - 1);
93	    v.GcVld(v.GcVld'low + 1 to v.GcVld'high)       := r.GcVld(r.GcVld'low to r.GcVld'high - 1);
94	
95	    -- *** Stage Accu 0 ***
96	    -- Input Registers
97	    v.VldAccu(0) := vld_i;
98	    v.Input_0    := dat_i;
99	
100	    -- *** Stage Accu 1 ***
101	    -- First accumulator
102	    if r.VldAccu(0) = '1' then
103	      v.Accu(1) := psi_fix_add(r.Accu(1), AccuFmt_c,
104	                             r.Input_0, in_fmt_g,
105	                             AccuFmt_c);
106	    end if;
107	
108	    -- *** Accumuator Stages (2 to Order) ***
109	    for stage in 1 to order_g - 1 loop
110	      if r.VldAccu(stage) = '1' then
111	        v.Accu(stage + 1) := psi_fix_add(r.Accu(stage + 1), AccuFmt_c,
112	                                       r.Accu(stage), AccuFmt_c,
113	                                       AccuFmt_c);
114	      end if;
115	    end loop;
116	
117	    -- *** Stage Diff 0 ***
118	    -- Decimate
119	    v.VldDiff(0) := '0';
120	    if r.VldAccu(order_g) = '1' then
121	      if r.Rcnt = 0 then
122	        v.VldDiff(0) := '1';
123	        v.Rcnt       := ratio_g - 1;
124	        v.DiffIn_0   := psi_fix_shift_right(r.Accu(order_g), AccuFmt_c, Shift_c, Shift_c, DiffFmt_c, psi_fix_trunc, psi_fix_wrap);
125	      else
126	        v.Rcnt := r.Rcnt - 1;
127	      end if;
128	    end if;
129	
130	    -- *** Stage Diff 1 ***
131	    -- First differentiator
132	    if r.VldDiff(0) = '1' then
133	      if diff_delay_g = 1 then
134	        DiffDel_v := r.DiffLast(1);
135	      else
136	        DiffDel_v      := r.DiffLast2(1);
137	        v.DiffLast2(1) := r.DiffLast(1);
138	      end if;
139	      -- Differentiate
140	      v.DiffVal(1)  := psi_fix_sub(r.DiffIn_0, DiffFmt_c,
141	                                 DiffDel_v, DiffFmt_c,
142	                                 DiffFmt_c);
143	      v.DiffLast(1) := r.DiffIn_0;
144	    end if;
145	
146	    -- *** Diff Stages ***
147	    -- Differentiators
148	    for stage in 1 to order_g - 1 loop
149	      if r.VldDiff(stage) = '1' then
150	        if diff_delay_g = 1 then
151	          DiffDel_v := r.DiffLast(stage + 1);
152	        else
153	          DiffDel_v              := r.DiffLast2(stage + 1);
154	          v.DiffLast2(stage + 1) := r.DiffLast(stage + 1);
155	        end if;
156	        -- Differentiate
157	        v.DiffVal(stage + 1)  := psi_fix_sub(r.DiffVal(stage), DiffFmt_c,
158	                                           DiffDel_v, DiffFmt_c,
159	                                           DiffFmt_c);
160	        v.DiffLast(stage + 1) := r.DiffVal(stage);
161	      end if;
162	    end loop;
163	
164	    if auto_gain_corr_g then
165	      -- *** Gain Correction Stage 0 ***
166	      v.GcVld(0) := r.VldDiff(order_g);
167	      v.GcIn_0   := psi_fix_resize(r.DiffVal(order_g), DiffFmt_c, GcInFmt_c, psi_fix_round, psi_fix_sat);
168	
169	      -- *** Gain Correction Stage 1 ***
170	      v.GcMult_1 := psi_fix_mult(r.GcIn_0, GcInFmt_c,
171	                               Gc_c, GcCoefFmt_c,
172	                               GcMultFmt_c, psi_fix_trunc, psi_fix_wrap); -- Round/Truncation in next stage
173	      v.GcOut_2  := psi_fix_resize(r.GcMult_1, GcMultFmt_c, out_fmt_g, psi_fix_round, psi_fix_sat);
174	    end if;
175	
176	    -- *** Status Output ***
177	    if (unsigned(r.VldAccu) /= 0) or (unsigned(r.VldDiff) /= 0) or (unsigned(r.GcVld) /= 0) then -- OutVld omitted because of 1 cycle PL delay
178	      v.CalcOngoing := '1';
179	    else
180	      v.CalcOngoing := '0';
181	    end if;
182	
183	    -- *** Output Assignment ***
184	    if auto_gain_corr_g then
185	      v.Outp   := r.GcOut_2;
186	      v.OutVld := r.GcVld(2);
187	    else
188	      v.Outp   := psi_fix_resize(r.DiffVal(order_g), DiffFmt_c, out_fmt_g, psi_fix_round, psi_fix_sat);
189	      v.OutVld := r.VldDiff(order_g);
190	    end if;
191	    busy_o <= r.CalcOngoing or r.VldAccu(0);
192	
193	    -- Apply to record
194	    r_next <= v;
195	
196	  end process;
197	
198	  --------------------------------------------------------------------------
199	  -- Output Assignment
200	  --------------------------------------------------------------------------
201	  vld_o <= r.OutVld;
202	  dat_o <= r.Outp;
203	
204	  --------------------------------------------------------------------------
205	  -- Sequential Process
206	  --------------------------------------------------------------------------
207	  p_seq : process(clk_i)
208	  begin
209	    if rising_edge(clk_i) then
210	      r <= r_next;
211	      if rst_i = rst_pol_g then
212	        r.VldAccu     <= (others => '0');
213	        r.Accu        <= (others => (others => '0'));
214	        r.Rcnt        <= 0;
215	        r.VldDiff     <= (others => '0');
216	        r.DiffLast    <= (others => (others => '0'));
217	        r.DiffLast2   <= (others => (others => '0'));
218	        r.GcVld       <= (others => '0');
219	        r.OutVld      <= '0';
220	        r.CalcOngoing <= '0';
221	      end if;
222	    end if;
223	  end process;
224	
225	end architecture;
