28	    rst_i : in  std_logic;                                             -- rst system
29	    dat_i : in  std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0); -- data input
30	    vld_i : in  std_logic;                                             -- valid input Frequency sampling
31	    rdy_o : out std_logic;                                             -- ready signal output
32	    dat_o : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);-- data output
33	    vld_o : out std_logic;                                             -- valid signal output new Fs*Ratio
34	    rdy_i : in  std_logic                                              -- ready signal input
35	  );
36	end entity;
37	-- @formatter : on
38	architecture rtl of psi_fix_cic_int_fix_1ch is
39	  -- Constants
40	  constant CicGain_c     : real                                                   := ((real(ratio_g) * real(diff_delay_g))**real(order_g)) / real(ratio_g);
41	  constant CicAddBits_c  : integer                                                := log2ceil(CicGain_c - 0.1); -- WORKAROUND: Vivado does real calculations imprecisely. With the -0.1, wrong results are avoided.
42	  constant Shift_c       : integer                                                := CicAddBits_c;
43	  constant DiffFmt_c     : psi_fix_fmt_t                                            := (in_fmt_g.S, in_fmt_g.I + order_g + 1, in_fmt_g.F);
44	  constant AccuFmt_c     : psi_fix_fmt_t                                            := (in_fmt_g.S, in_fmt_g.I + CicAddBits_c, in_fmt_g.F);
45	  constant ShiftInFmt_c  : psi_fix_fmt_t                                            := (in_fmt_g.S, in_fmt_g.I, in_fmt_g.F + CicAddBits_c);
46	  constant GcInFmt_c     : psi_fix_fmt_t                                            := (1, out_fmt_g.I, work.psi_common_math_pkg.min(24 - out_fmt_g.I, ShiftInFmt_c.F));
47	  constant ShiftOutFmt_c : psi_fix_fmt_t                                            := (in_fmt_g.S, in_fmt_g.I, choose(auto_gain_corr_g, GcInFmt_c.F, out_fmt_g.F) + 1);
48	  constant GcCoefFmt_c   : psi_fix_fmt_t                                            := (0, 1, 16);
49	  constant GcMultFmt_c   : psi_fix_fmt_t                                            := (1, GcInFmt_c.I + GcCoefFmt_c.I, GcInFmt_c.F + GcCoefFmt_c.F);
50	  constant Gc_c          : std_logic_vector(psi_fix_size(GcCoefFmt_c) - 1 downto 0) := psi_fix_from_real(2.0**real(CicAddBits_c) / real(CicGain_c), GcCoefFmt_c);
51	
52	  -- Types
53	  type Accus_t is array (natural range <>) of std_logic_vector(psi_fix_size(AccuFmt_c) - 1 downto 0);
54	  type Diff_t is array (natural range <>) of std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
55	
56	  -- Two Process Method
57	  type two_process_r is record
58	    -- Diff Section
59	    Input_0   : std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);
60	    Rdy_0     : std_logic;
61	    VldDiff   : std_logic_vector(0 to order_g);
62	    DiffVal   : Diff_t(1 to order_g);
63	    DiffLast  : Diff_t(1 to order_g);
64	    DiffLast2 : Diff_t(1 to order_g);
65	    -- Interplation
66	    Rcnt      : integer range 0 to ratio_g;
67	    VldAccu   : std_logic_vector(0 to order_g);
68	    AccuIn_0  : std_logic_vector(psi_fix_size(AccuFmt_c) - 1 downto 0);
69	    -- Accu section
70	    Accu      : Accus_t(1 to order_g);
71	    -- GC Stages
72	    GcVld     : std_logic_vector(0 to 4);
73	    GcIn_0    : std_logic_vector(psi_fix_size(GcInFmt_c) - 1 downto 0);
74	    GcIn_1    : std_logic_vector(psi_fix_size(GcInFmt_c) - 1 downto 0);
75	    GcIn_2    : std_logic_vector(psi_fix_size(GcInFmt_c) - 1 downto 0);
76	    GcMult_3  : std_logic_vector(psi_fix_size(GcMultFmt_c) - 1 downto 0);
77	    GcOut_4   : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
78	    -- Output
79	    Outp      : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
80	    OutVld    : std_logic;
81	  end record;
82	  signal r, r_next : two_process_r;
83	
84	begin
85	  --------------------------------------------------------------------------
86	  -- Combinatorial Process
87	  --------------------------------------------------------------------------
88	  p_comb : process(r, dat_i, vld_i, rdy_i)
89	    variable v         : two_process_r;
90	    variable DiffDel_v : std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
91	    variable Sft_v     : std_logic_vector(psi_fix_size(ShiftOutFmt_c) - 1 downto 0);
92	    variable InRdy_v   : std_logic;
93	    variable OutRdy_v  : std_logic;
94	  begin
95	    -- hold variables stable
96	    v := r;
97	
98	    -- Variable default values
99	    DiffDel_v := (others => '0');
100	    Sft_v     := (others => '0');
101	
102	    -- *** Handshaking pipeline control signals ***
103	    -- Only stop output pipeline if a result is available at the output (AXI-S Spec says valid is not allowed to wait on ready!)
104	    if r.OutVld = '0' or rdy_i = '1' then
105	      OutRdy_v := '1';
106	    else
107	      OutRdy_v := '0';
108	    end if;
109	
110	    -- Input Rdy
111	    if r.Rcnt = 0 or (r.Rcnt = 1 and OutRdy_v = '1') then
112	      InRdy_v := '1';
113	    else
114	      InRdy_v := '0';
115	    end if;
116	
117	    -- *** Pipe Handling ***
118	    if InRdy_v = '1' then
119	      v.VldDiff(v.VldDiff'low + 1 to v.VldDiff'high) := r.VldDiff(r.VldDiff'low to r.VldDiff'high - 1);
120	    end if;
121	    if OutRdy_v = '1' then
122	      v.VldAccu(v.VldAccu'low + 1 to v.VldAccu'high) := r.VldAccu(r.VldAccu'low to r.VldAccu'high - 1);
123	      v.GcVld(v.GcVld'low + 1 to v.GcVld'high)       := r.GcVld(r.GcVld'low to r.GcVld'high - 1);
124	    end if;
125	
126	    -- *** Stage Diff 0 (Input registers) ***
127	    -- Input Registers and combinatorial rdy chain breaking (making RDY registered)
128	    if r.Rdy_0 = '1' and vld_i = '1' then
129	      v.VldDiff(0) := '1';
130	      v.Input_0    := dat_i;
131	      v.Rdy_0      := '0';
132	    elsif InRdy_v = '1' or r.VldDiff(1) = '0' then
133	      v.VldDiff(0) := '0';
134	      v.Rdy_0      := '1';
135	    end if;
136	
137	    -- *** Stage Diff 1 ***
138	    -- First differentiator
139	    if r.VldDiff(0) = '1' and (InRdy_v = '1' or r.VldDiff(1) = '0') then
140	      v.VldDiff(1)  := '1';
141	      v.VldDiff(0)  := '0';
142	      if diff_delay_g = 1 then
143	        DiffDel_v := r.DiffLast(1);
144	      else
145	        DiffDel_v      := r.DiffLast2(1);
146	        v.DiffLast2(1) := r.DiffLast(1);
147	      end if;
148	      -- Differentiate
149	      v.DiffVal(1)  := psi_fix_sub(r.Input_0, in_fmt_g,
150	                                 DiffDel_v, DiffFmt_c,
151	                                 DiffFmt_c);
152	      v.DiffLast(1) := psi_fix_resize(r.Input_0, in_fmt_g, DiffFmt_c);
153	    end if;
154	
155	    -- *** Diff Stages ***
156	    -- Differentiators
157	    for stage in 1 to order_g - 1 loop
158	      if r.VldDiff(stage) = '1' and (InRdy_v = '1' or r.VldDiff(stage + 1) = '0') then
159	        v.VldDiff(stage + 1)  := '1';
160	        v.VldDiff(stage)      := r.VldDiff(stage - 1);
161	        if diff_delay_g = 1 then
162	          DiffDel_v := r.DiffLast(stage + 1);
163	        else
164	          DiffDel_v              := r.DiffLast2(stage + 1);
165	          v.DiffLast2(stage + 1) := r.DiffLast(stage + 1);
166	        end if;
167	        -- Differentiate
168	        v.DiffVal(stage + 1)  := psi_fix_sub(r.DiffVal(stage), DiffFmt_c,
169	                                           DiffDel_v, DiffFmt_c,
170	                                           DiffFmt_c);
171	        v.DiffLast(stage + 1) := r.DiffVal(stage);
172	      end if;
173	    end loop;
174	
175	    -- *** Stage Accu 0 (interpolation) ***
176	    if (r.Rcnt = 0 and r.VldDiff(order_g) = '1') or (r.Rcnt = 1 and OutRdy_v = '1' and r.VldDiff(order_g) = '1') then
177	      v.Rcnt       := ratio_g;
178	      v.AccuIn_0   := psi_fix_resize(r.DiffVal(order_g), DiffFmt_c, AccuFmt_c);
179	      v.VldAccu(0) := '1';
180	    elsif r.Rcnt = 1 and OutRdy_v = '1' then
181	      v.VldAccu(0) := '0';
182	      v.Rcnt       := r.Rcnt - 1;
183	    elsif OutRdy_v = '1' and r.Rcnt /= 0 then
184	      v.AccuIn_0 := (others => '0');
185	      v.Rcnt     := r.Rcnt - 1;
186	    end if;
187	
188	    -- *** Stage Accu 1 ***
189	    -- First accumulator
190	    if r.VldAccu(0) = '1' and OutRdy_v = '1' then
191	      v.Accu(1) := psi_fix_add(r.Accu(1), AccuFmt_c,
192	                             r.AccuIn_0, AccuFmt_c,
193	                             AccuFmt_c);
194	    end if;
195	
196	    -- *** Accumuator Stages (2 to Order) ***
197	    for stage in 1 to order_g - 1 loop
198	      if r.VldAccu(stage) = '1' and OutRdy_v = '1' then
199	        v.Accu(stage + 1) := psi_fix_add(r.Accu(stage + 1), AccuFmt_c,
200	                                       r.Accu(stage), AccuFmt_c,
201	                                       AccuFmt_c);
202	      end if;
203	    end loop;
204	    -- Shifter (pure wiring)
205	    Sft_v := psi_fix_shift_right(r.Accu(order_g), AccuFmt_c, Shift_c, Shift_c, ShiftOutFmt_c);
206	
207	    -- *** Gain Correction ***
208	    if auto_gain_corr_g then
209	      -- *** Gain Correction Stage 0 ***
210	      if OutRdy_v = '1' then
211	        -- *** GC Stage 0 ***
212	        v.GcVld(0) := r.VldAccu(order_g);
213	        v.GcIn_0   := psi_fix_resize(Sft_v, ShiftOutFmt_c, GcInFmt_c, psi_fix_round, psi_fix_sat);
214	
215	        -- *** GC Stage 1 ***
216	        v.GcIn_1 := r.GcIn_0;
217	
218	        -- *** GC Stage 2 ***
219	        v.GcIn_2 := r.GcIn_1;
220	
221	        -- *** Gain Correction Stage 3 ***
222	        v.GcMult_3 := psi_fix_mult(r.GcIn_2, GcInFmt_c,
223	                                 Gc_c, GcCoefFmt_c,
224	                                 GcMultFmt_c, psi_fix_trunc, psi_fix_wrap); -- Round/Truncation in next stage
225	
226	        -- *** Gain Correction Stage 4 ***
227	        v.GcOut_4 := psi_fix_resize(r.GcMult_3, GcMultFmt_c, out_fmt_g, psi_fix_round, psi_fix_sat);
228	      end if;
229	    end if;
230	
231	    -- *** Output Assignment ***
232	    if OutRdy_v = '1' then
233	      if auto_gain_corr_g then
234	        v.Outp   := r.GcOut_4;
235	        v.OutVld := r.GcVld(4);
236	      else
237	        v.Outp   := psi_fix_resize(Sft_v, ShiftOutFmt_c, out_fmt_g, psi_fix_round, psi_fix_sat);
238	        v.OutVld := r.VldAccu(order_g);
239	      end if;
240	    end if;
241	
242	    -- *** Output Signals ***
243	    vld_o <= r.OutVld;
244	    dat_o <= r.Outp;
245	    rdy_o <= r.Rdy_0;
246	
247	    -- Apply to record
248	    r_next <= v;
249	
250	  end process;
251	
252	  --------------------------------------------------------------------------
253	  -- Sequential Process
254	  --------------------------------------------------------------------------
255	  p_seq : process(clk_i)
256	  begin
257	    if rising_edge(clk_i) then
258	      r <= r_next;
259	      if rst_i = rst_pol_g then
260	        r.VldDiff   <= (others => '0');
261	        r.DiffLast  <= (others => (others => '0'));
262	        r.DiffLast2 <= (others => (others => '0'));
263	        r.VldAccu   <= (others => '0');
264	        r.Accu      <= (others => (others => '0'));
265	        r.GcVld     <= (others => '0');
266	        r.OutVld    <= '0';
267	        r.Rdy_0     <= '1';
268	      end if;
269	    end if;
270	  end process;
271	
272	end architecture;
273

